#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        double Vx, Vy, R1x, R1y, R2x, R2y;
        scanf("%lf %lf %lf %lf %lf %lf", &Vx, &Vy, &R1x, &R1y, &R2x, &R2y);
        double angle = atan2(R2y - Vy, R2x - Vx) - atan2(R1y - Vy, R1x - Vx);
        if (angle < 0) angle += 2 * M_PI;
        int N = (int)round(angle * 180 / M_PI);
        if ((N & (N - 1)) == 0) {
            printf("YES\n");
            // Construct the rays
            for (int i = 1; i < N; i++) {
                double rayAngle = i * M_PI / N;
                double Dx = Vx + cos(rayAngle), Dy = Vy + sin(rayAngle);
                printf("%lf %lf\n", Dx, Dy);
            }
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

