import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            double Vx = sc.nextDouble(), Vy = sc.nextDouble(), R1x = sc.nextDouble(), R1y = sc.nextDouble(), R2x = sc.nextDouble(), R2y = sc.nextDouble();
            double angle = Math.atan2(R2y - Vy, R2x - Vx) - Math.atan2(R1y - Vy, R1x - Vx);
            if (angle < 0) angle += 2 * Math.PI;
            int N = (int)Math.round(angle * 180 / Math.PI);
            if ((N & (N - 1)) == 0) {
                System.out.println("YES");
                // Construct the rays
                for (int i = 1; i < N; i++) {
                    double rayAngle = i * Math.PI / N;
                    double Dx = Vx + Math.cos(rayAngle), Dy = Vy + Math.sin(rayAngle);
                    System.out.println(Dx + " " + Dy);
                }
            } else {
                System.out.println("NO");
            }
        }
    }
}

