        console.log('YES');
        // Construct the rays
        for (let j = 1; j < N; j++) {
            const rayAngle = j * Math.PI / N;
            const Dx = Vx + Math.cos(rayAngle);
            const Dy = Vy + Math.sin(rayAngle);
            console.log(Dx, Dy);
        }
